```csharp
public class Health
{
    public float CurrentHealth { get; set; }
    public float MaximumHealth { get; set; }
    public float HealthRegenerationPerSecond { get; set; }

    public float EffectiveHealthRegenerationPerSecond
    {
        get { return CurrentHealth * HealthRegenerationPerSecond / MaximumHealth; }
    }

    public void SetCurrentHealth(float value)
    {
        CurrentHealth = Mathf.Clamp(value, 0, MaximumHealth);
    }

    public void UpdateHealth()
    {
        SetCurrentHealth(CurrentHealth + EffectiveHealthRegenerationPerSecond);
    }
}

public class Player
{
    public Health Health { get; set; }

    public Player()
    {
        Health = new Health();
        Health.CurrentHealth = 100;
        Health.MaximumHealth = 100;
        Health.HealthRegenerationPerSecond = 5;
    }

    public void DisplayHealth()
    {
        Console.WriteLine("当前生命值：" + Health.CurrentHealth);
        Console.WriteLine("每秒生命恢复速率：" + Health.EffectiveHealthRegenerationPerSecond);
    }
}

public class Enemy
{
    public Health Health { get; set; }

    public Enemy()
    {
        Health = new Health();
        Health.CurrentHealth = 80;
        Health.MaximumHealth = 80;
        Health.HealthRegenerationPerSecond = 3;
    }

    public void DisplayHealth()
    {
        Console.WriteLine("当前生命值：" + Health.CurrentHealth);
        Console.WriteLine("每秒生命恢复速率：" + Health.EffectiveHealthRegenerationPerSecond);
    }
}

// 使用示例
Player player = new Player();
player.DisplayHealth();
player.Health.UpdateHealth();
player.DisplayHealth();

Enemy enemy = new Enemy();
enemy.DisplayHealth();
enemy.Health.UpdateHealth();
enemy.DisplayHealth();
```

在这个示例中，我们创建了Player和Enemy两个类，并在它们各自的构造函数中初始化了Health对象。Player和Enemy类中都有一个Health属性，可以通过这个属性访问和操作Health对象的当前生命值、最大生命值和生命恢复速率。

在使用示例中，我们创建了一个Player对象和一个Enemy对象，并分别展示了它们的当前生命值和每秒生命恢复速率。之后通过调用Health对象的UpdateHealth方法，模拟了每秒更新生命值的过程，并再次展示了更新后的生命状态。

